SELECT a.member_id AS memberId, a.store_id AS storeId, MAX(a.coach_id) AS coachId, COUNT(*) AS cnt FROM pt_private_appointment a WHERE a.appointment_status = 2 AND a.deleted = 0 AND a.cancel_at >= #{periodStart} AND a.cancel_at < DATE_ADD(#{periodEnd}, INTERVAL 1 DAY)
AND a.store_id IN
#{sid}
GROUP BY a.member_id, a.store_id HAVING COUNT(*) >= #{threshold}

SELECT a.member_id AS memberId, a.store_id AS storeId, MAX(a.coach_id) AS coachId, COUNT(*) AS cnt FROM pt_private_appointment a WHERE a.appointment_status = 3 AND a.deleted = 0 AND a.finish_at >= #{periodStart} AND a.finish_at < DATE_ADD(#{periodEnd}, INTERVAL 1 DAY)
AND a.store_id IN
#{sid}
GROUP BY a.member_id, a.store_id HAVING COUNT(*) >= #{threshold}
